// // This module implements a sequential latch circuit with a reset and clock input. It maintains a wide data output (32 bits by default) based on a 2-bit control signal. When the reset signal is active, the output is set to zero. On the rising edge of the clock, if the control signal is 00, it captures and outputs the incoming data; if the control signal is 01, it outputs zero; otherwise, it retains its previous value.
module top_module(rst, clk, ctr, data_in, data_out);parameter N=32;

  input rst;
  input clk;
  input [1:0] ctr; 
  input [N-1:0] data_in;
  output reg [N-1:0] data_out;

  always @(posedge clk) begin
    if (rst) begin
      data_out <= 0;
    end else begin
      case (ctr)
        2'b00  : data_out <= data_in;
        2'b01  : data_out <= 0;
        default: data_out <= data_out;
      endcase 
    end
  end
endmodule
